import React, { useState } from 'react';
import { BrowserRouter as Router, Routes, Route, Navigate } from 'react-router-dom';
import JobListContainer from './features/eksplorasi/JobListContainer';
import FavoriteListContainer from './features/eksplorasi/FavoriteListContainer';
import Login from './components/auth/Login'; 
import Register from './components/auth/Register';
import StatusLamaran from './features/applications/StatusTracker';
import ProfilSaya from './features/dashboard/ProfileContainer';
// Mengganti Sidebar dengan Navbar
import Navbar from './components/Navbar/Navbar'; 
import Footer from './components/Footer/Footer';

const App = () => {
    const [isAuthenticated, setIsAuthenticated] = useState(!!localStorage.getItem('token'));
    const [activeMenu, setActiveMenu] = useState('eksplorasi');
    const [appTheme] = useState('dark');

    const handleLogout = () => {
        localStorage.removeItem('token');
        localStorage.removeItem('role');
        localStorage.removeItem('user_name');
        setIsAuthenticated(false);
        window.location.href = '/login';
    };

    return (
        <Router>
            <Routes>
                {/* Rute Publik */}
                <Route path="/login" element={
                    isAuthenticated ? <Navigate to="/" /> : <Login onLoginSuccess={() => setIsAuthenticated(true)} />
                } />
                <Route path="/register" element={<Register />} />

                {/* Rute Terproteksi (Homepage dengan Navbar & Footer) */}
                <Route path="/" element={
                    isAuthenticated ? (
                        <div style={{ 
                            display: 'flex', 
                            flexDirection: 'column', 
                            minHeight: '100vh', 
                            background: '#080402',
                            color: '#fff' 
                        }}>
                            {/* Navbar sebagai pengganti Sidebar */}
                            <Navbar 
    activeMenu={activeMenu} 
    setActiveMenu={setActiveMenu} 
    isAuthenticated={isAuthenticated} // Penting!
    handleLogout={handleLogout} 
/>

                            {/* Main Content Area */}
                            <main style={{ 
                                flex: 1, 
                                display: 'flex', 
                                flexDirection: 'column',
                                padding: '40px 80px', // Memberikan ruang lebar khas homepage
                                maxWidth: '1400px',
                                margin: '0 auto',
                                width: '100%'
                            }}>
                                {activeMenu === 'eksplorasi' && <JobListContainer appTheme={appTheme} />}
                                {activeMenu === 'favorit'    && <FavoriteListContainer appTheme={appTheme} />}
                                {activeMenu === 'status'     && <StatusLamaran appTheme={appTheme} />}
                                {activeMenu === 'profil'     && <ProfilSaya appTheme={appTheme} />}
                            </main>

                            {/* Footer Baru */}
                            <Footer />
                        </div>
                    ) : <Navigate to="/login" />
                } />
            </Routes>
        </Router>
    );
};

export default App;
